patch:
diff --git a/llvm/lib/Analysis/ValueTracking.cpp b/llvm/lib/Analysis/ValueTracking.cpp
index 973943790c0a..857f886ad427 100644
--- a/llvm/lib/Analysis/ValueTracking.cpp
+++ b/llvm/lib/Analysis/ValueTracking.cpp
@@ -8292,6 +8292,86 @@ static std::optional<bool> isImpliedCondICmps(const ICmpInst *LHS,
   if (L0 == R0 && match(L1, m_APInt(LC)) && match(R1, m_APInt(RC)))
     return isImpliedCondCommonOperandWithConstants(LPred, *LC, RPred, *RC);

+
+
+
+
+
+  // A + B u< A  iff  A + B u< B
+  // A + B u>= A iff  A + B u>= B
+  // If the compares match after swapping operands, they are equivalent.
+  if (match(L0, m_Add(m_Value(), m_Value())) && L0 == R0) {
+    const Instruction *Add = cast<Instruction>(L0);
+    Value *X = Add->getOperand(0);
+    Value *Y = Add->getOperand(1);
+    if ((L1 == X && R1 == Y) || (L1 == Y && R1 == X)) {
+      if (LPred == RPred && (LPred == CmpInst::ICMP_ULT || LPred == CmpInst::ICMP_UGE || LPred == CmpInst::ICMP_ULE || LPred == CmpInst::ICMP_UGT))
+        return true;
+      if (LPred == CmpInst::getInversePredicate(RPred) && (LPred == CmpInst::ICMP_ULT || LPred == CmpInst::ICMP_UGE || LPred == CmpInst::ICMP_ULE || LPred == CmpInst::ICMP_UGT))
+        return false;
+    }
+  }
+
+  // Handle swapped operands where one is a sum:
+  // (A u> A + B) iff (B u> A + B)
+  // (A u<= A + B) iff (B u<= A + B)
+  if (match(L1, m_Add(m_Value(), m_Value())) && L1 == R1) {
+    const Instruction *Add = cast<Instruction>(L1);
+    Value *X = Add->getOperand(0);
+    Value *Y = Add->getOperand(1);
+    if ((L0 == X && R0 == Y) || (L0 == Y && R0 == X)) {
+      if (LPred == RPred && (LPred == CmpInst::ICMP_ULT || LPred == CmpInst::ICMP_UGE || LPred == CmpInst::ICMP_ULE || LPred == CmpInst::ICMP_UGT))
+        return true;
+      if (LPred == CmpInst::getInversePredicate(RPred) && (LPred == CmpInst::ICMP_ULT || LPred == CmpInst::ICMP_UGE || LPred == CmpInst::ICMP_ULE || LPred == CmpInst::ICMP_UGT))
+        return false;
+    }
+  }
+
+  // A + B u< A  iff  B u> A + B
+  // If the compares match after swapping operands and sides, they are equivalent.
+  if (match(L0, m_Add(m_Value(), m_Value())) && L0 == R1) {
+    const Instruction *Add = cast<Instruction>(L0);
+    Value *X = Add->getOperand(0);
+    Value *Y = Add->getOperand(1);
+    if ((L1 == X && R0 == Y) || (L1 == Y && R0 == X)) {
+      CmpInst::Predicate SwappedRPred = CmpInst::getSwappedPredicate(RPred);
+      if (LPred == SwappedRPred && (LPred == CmpInst::ICMP_ULT || LPred == CmpInst::ICMP_UGE || LPred == CmpInst::ICMP_ULE || LPred == CmpInst::ICMP_UGT))
+        return true;
+      if (LPred == CmpInst::getInversePredicate(SwappedRPred) && (LPred == CmpInst::ICMP_ULT || LPred == CmpInst::ICMP_UGE || LPred == CmpInst::ICMP_ULE || LPred == CmpInst::ICMP_UGT))
+        return false;
+    }
+  }
+
+  // (A u> A + B) iff (A + B u< B)
+  if (match(L1, m_Add(m_Value(), m_Value())) && L1 == R0) {
+    const Instruction *Add = cast<Instruction>(L1);
+    Value *X = Add->getOperand(0);
+    Value *Y = Add->getOperand(1);
+    if ((L0 == X && R1 == Y) || (L0 == Y && R1 == X)) {
+      CmpInst::Predicate SwappedRPred = CmpInst::getSwappedPredicate(RPred);
+      if (LPred == SwappedRPred && (LPred == CmpInst::ICMP_ULT || LPred == CmpInst::ICMP_UGE || LPred == CmpInst::ICMP_ULE || LPred == CmpInst::ICMP_UGT))
+        return true;
+      if (LPred == CmpInst::getInversePredicate(SwappedRPred) && (LPred == CmpInst::ICMP_ULT || LPred == CmpInst::ICMP_UGE || LPred == CmpInst::ICMP_ULE || LPred == CmpInst::ICMP_UGT))
+        return false;
+    }
+  }
+
+  // Handle swapped operands where one is a sum:
+  // (A u> A + B) iff (B u> A + B)
+  // (A u<= A + B) iff (B u<= A + B)
+  if (L1 == R1 && match(L1, m_Add(m_Value(), m_Value()))) {
+    const Instruction *Add = cast<Instruction>(L1);
+    Value *X = Add->getOperand(0);
+    Value *Y = Add->getOperand(1);
+    if ((L0 == X && R0 == Y) || (L0 == Y && R0 == X)) {
+      if (LPred == RPred && (LPred == CmpInst::ICMP_ULT || LPred == CmpInst::ICMP_UGE || LPred == CmpInst::ICMP_ULE || LPred == CmpInst::ICMP_UGT))
+        return true;
+      if (LPred == CmpInst::getInversePredicate(RPred) && (LPred == CmpInst::ICMP_ULT || LPred == CmpInst::ICMP_UGE || LPred == CmpInst::ICMP_ULE || LPred == CmpInst::ICMP_UGT))
+        return false;
+    }
+  }
+
+
   if (LPred == RPred)
     return isImpliedCondOperands(LPred, L0, L1, R0, R1, DL, Depth);
